async function genericTextToTextForward(self, {
    encode_function,              // self.encode_image
    merge_function,               // self._merge_input_ids_with_image_features
    modality_input_name,          // 'pixel_values'
    modality_output_name,         // 'image_features'

    input_ids = null,
    attention_mask = null,
    position_ids = null,
    inputs_embeds = null,
    past_key_values = null,
    generation_config = null,
    logits_processor = null,
    ...kwargs
}) {
    // 1. Extract text embeddings from input_ids
    inputs_embeds = await self.encode_text({ input_ids, ...kwargs });

    // 2. If image modality is provided, encode and merge with text
    if (modality_values && input_ids.dims[1] !== 1) {
        const modality_features = await encode_function({
            [modality_input_name]: modality_values,  // pixel_values
            ...kwargs
        });
        ({ inputs_embeds, attention_mask } = merge_function({
            [modality_output_name]: modality_features,  // image_features
            inputs_embeds,
            input_ids,
            attention_mask,
        }));
    }

    // 3. Call decoder forward
    const outputs = await decoderForward(self, {
        inputs_embeds,
        past_key_values,
        attention_mask,
        position_ids,
        generation_config,
        logits_processor,
    }, true);
    return outputs;
}
