8	
9	    constructor(config, components, chat_template) {
10	        super(config, components, chat_template);
11	
12	        const {
13	            // @ts-expect-error TS2339
14	            tasks_answer_post_processing_type,
15	            // @ts-expect-error TS2339
16	            task_prompts_without_inputs,
17	            // @ts-expect-error TS2339
18	            task_prompts_with_input,
19	        } = this.image_processor.config;
20	
21	        /** @type {Map<string, string>} */
22	        this.tasks_answer_post_processing_type = new Map(Object.entries(tasks_answer_post_processing_type ?? {}));
23	
24	        /** @type {Map<string, string>} */
25	        this.task_prompts_without_inputs = new Map(Object.entries(task_prompts_without_inputs ?? {}));
26	
27	        /** @type {Map<string, string>} */
28	        this.task_prompts_with_input = new Map(Object.entries(task_prompts_with_input ?? {}));
29	
30	        this.regexes = {
31	            quad_boxes: /(.+?)<loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)>/gm,
32	            bboxes: /([^<]+)?<loc_(\d+)><loc_(\d+)><loc_(\d+)><loc_(\d+)>/gm,
33	        }
34	        this.size_per_bin = 1000;
35	    }
36	
37	    /**
38	     * Helper function to construct prompts from input texts
39	     * @param {string|string[]} text
40	     * @returns {string[]}
41	     */
42	    construct_prompts(text) {
43	        if (typeof text === 'string') {
44	            text = [text];
45	        }
46	
47	        const prompts = [];
48	        for (const t of text) {
49	            // 1. fixed task prompts without additional inputs
50	            if (this.task_prompts_without_inputs.has(t)) {
51	                prompts.push(this.task_prompts_without_inputs.get(t));
52	            }
53	            // 2. task prompts with additional inputs 
54	            else {
55	                for (const [task, prompt] of this.task_prompts_with_input) {
56	                    if (t.includes(task)) {
57	                        prompts.push(prompt.replaceAll('{input}', t).replaceAll(task, ''));
58	                        break;
59	                    }
60	                }
61	
62	                // 3. default prompt
63	                if (prompts.length !== text.length) {
64	                    prompts.push(t);
65	                }
66	            }
67	        }
68	        return prompts;
69	    }
70	
71	    /**
72	     * Post-process the output of the model to each of the task outputs.
73	     * @param {string} text The text to post-process.
74	     * @param {string} task The task to post-process the text for.
75	     * @param {[number, number]} image_size The size of the image. height x width.
76	     */
77	    post_process_generation(text, task, image_size) {
78	        const task_answer_post_processing_type = this.tasks_answer_post_processing_type.get(task) ?? 'pure_text';
79	
80	        // remove the special tokens
81	        text = text.replaceAll('<s>', '').replaceAll('</s>', '');
82	
83	        let final_answer;
84	        switch (task_answer_post_processing_type) {
85	            case 'pure_text':
86	                final_answer = text;
87	                break;
88	
89	            case 'description_with_bboxes':
90	            case 'bboxes':
91	            case 'phrase_grounding':
92	            case 'ocr':
93	                const key = task_answer_post_processing_type === 'ocr' ? 'quad_boxes' : 'bboxes';
94	                const matches = text.matchAll(this.regexes[key]);
95	                const labels = [];
96	                const items = [];
97	                for (const [_, label, ...locations] of matches) {
98	                    // Push new label, or duplicate the last label
99	                    labels.push(label ? label.trim() : labels.at(-1) ?? '');
100	                    items.push(locations.map((x, i) =>
101	                        // NOTE: Add 0.5 to use the center position of the bin as the coordinate.
102	                        (Number(x) + 0.5) / this.size_per_bin * image_size[i % 2])
103	                    );
104	                }
105	                final_answer = { labels, [key]: items };
106	                break;
107	
108	            default:
109	                throw new Error(`Task "${task}" (of type "${task_answer_post_processing_type}") not yet implemented.`);
110	        }
111	
112	        return { [task]: final_answer }
113	    }
114	
115	    // NOTE: images and text are switched from the python version
116	    // `images` is required, `text` is optional
117	    async _call(images, text=null, kwargs = {}) {
118	
119	        if (!images && !text){
120	            throw new Error('Either text or images must be provided');
121	        }
122	
123	        const image_inputs = await this.image_processor(images, kwargs);
124	        const text_inputs = text ? this.tokenizer(this.construct_prompts(text), kwargs) : {};
125	
126	        return {
127	            ...image_inputs,
128	            ...text_inputs,
129	        }
130	    }
131	}
