27	    async _call(/** @type {RawImage|RawImage[]} */ images, text = null, kwargs = {}) {
28	        if (!text) {
29	            console.warn(
30	                "You are using PaliGemma without a text prefix. It will perform as a picture-captioning model."
31	            )
32	            text = ""
33	        }
34	
35	        if (!Array.isArray(images)) {
36	            images = [images]
37	        }
38	
39	        if (!Array.isArray(text)) {
40	            text = [text]
41	        }
42	
43	        const bos_token = this.tokenizer.bos_token;
44	        // @ts-expect-error TS2339
45	        const image_seq_length = this.image_processor.config.image_seq_length;
46	        let input_strings;
47	        if (text.some((t) => t.includes(IMAGE_TOKEN))) {
48	            input_strings = text.map(
49	                sample => {
50	                    const expanded_sample = sample.replaceAll(IMAGE_TOKEN, IMAGE_TOKEN.repeat(image_seq_length));
51	                    const bos_rfind_index = expanded_sample.lastIndexOf(IMAGE_TOKEN);
52	                    const bos_index = bos_rfind_index === -1 ? 0 : bos_rfind_index + IMAGE_TOKEN.length;
53	                    return expanded_sample.slice(0, bos_index) + bos_token + expanded_sample.slice(bos_index) + "\n";
54	                }
55	            )
56	        } else {
57	            console.warn(
58	                "You are passing both `text` and `images` to `PaliGemmaProcessor`. The processor expects special " +
59	                "image tokens in the text, as many tokens as there are images per each text. It is recommended to " +
60	                "add `<image>` tokens in the very beginning of your text. For this call, we will infer how many images " +
61	                "each text has and add special tokens."
62	            )
63	
64	            input_strings = text.map(
65	                sample => build_string_from_input(
66	                    sample,
67	                    bos_token,
68	                    image_seq_length,
69	                    IMAGE_TOKEN,
70	                    images.length,
71	                )
72	            )
73	        }
74	
75	        const text_inputs = this.tokenizer(input_strings, kwargs);
76	        const image_inputs = await this.image_processor(images, kwargs);
